import { setTimeout } from "promise-timers";
import gameConfig from "../game_config.json"

const iceCounter = ({gameState}) => {
    let IceCounter = []
   
    for (let i = 1; i < gameConfig.iceLimit; i++) {
        if(i >= gameState.iceCounter) {
            IceCounter.unshift(<div className='icepowerOFF' key={i + "_icePower"}></div>)
        } else {
            IceCounter.unshift(<div className='icepowerON'key={i + "_icePower"}></div>)
        }
    };
    return (
    <div id="iceMetreContainer">
        <div id="iceText"><div id="a"><p id='blue'>ICE</p></div></div>
        <div id="IceCounter">{IceCounter}</div>
    </div>
    )
}



export default iceCounter