export class Client {
  constructor(gameState, cards) {
  


  }

  async addFadingClassToWins (wins) {

    
    let symbolGrid = window.document.getElementById("symbolGrid")

    
    // USING WIN ID, ONLY WORKS FOR OCCURANCE
    // let winningIds = []
    // wins.forEach(async (win) => {
    //   winningIds.push(win.id)
    // });

    // for (const child of symbolGrid.children) {
    //   winningIds.includes(child.textContent)
    //   if(winningIds.includes(parseInt(child.textContent)) && !child.className.includes("frozen")) {
    //     child.className += " winAnimationClass"
    //   }
    // }
    let winningPositions = []
    wins.forEach(async (win) => {
      winningPositions = [...winningPositions, ...win.pos]
    });

    let index = 0
    for (const child of symbolGrid.children) {
      if(winningPositions.includes(index) && !child.className.includes("frozen")) {
        child.className += " winAnimationClass"
      }
      index++
    }



  }
}

export default Client
