import { setTimeout } from "promise-timers";
import gameConfig from "../game_config.json"

const NukeCounter = ({gameState}) => {
    let nukeCounter = []
   
    for (let i = 1; i < gameConfig.nukeLimit; i++) {
        if(i >= gameState.nukeCounter) {
            nukeCounter.unshift(<div className='powerOFF' key={i + "_nukePower"}></div>)
        } else {
            nukeCounter.unshift(<div className='powerON'key={i + "_nukePower"}></div>)
        }
    };
    return (
    <div id="nukeContainer">
        <div id="nukeText"><div id="a"><p id='red'>NUKE</p></div></div>
        <div id="nukeCounter">{nukeCounter}</div>
    </div>
    )
}



export default NukeCounter