import gameConfig from '../game_config.json'

const Bottombar = ({gameState, wallet}) => {
    return (
        <div className="wallet">
            <h3 style={bottombarStyle}>{`TOTAL PAYOUT: ${gameState.tbm}`}</h3>
            <h3 style={bottombarStyle}>{`NUKE COUNTER: ${gameState.nukeCounter} / ${gameConfig.nukeLimit}`}</h3>
            <h3 style={bottombarStyle}>{`ICE COUNTER: ${gameState.iceCounter} / ${gameConfig.iceLimit}`}</h3>
        </div>


    )
}
//<h3 style={bottombarStyle}>{`Flares: ${gameState.flares}`}</h3>
const bottombarStyle = {
    color: 'black',
    backgroundColor: 'grey',
    paddingLeft: "5px"
}

export default Bottombar