let space_background = '/images/realistic-galaxy-background.jpg'

const Area_1 = ({title}) => {
    return (
        <div style={Area_1Style} className="title">
           
            <div className="Area_1">
                <h1 style={Area_1Style} >{title}</h1>
            </div>
            
            <marquee className={'banner'} width="100%" direction="right" height="2%" behavior="sliding" scrollamount="4">Crack!</marquee>
        </div>
    )
}
//<div style={Area_2Style} className={'wii'}>{divider}</div>
//<div style={Area_Top_Style} className={'wii'}>{divider}</div>
Area_1.defaultProps = {
    title: 'Icebrejk',
}

const Area_1Style = {
    padding: "5px",
    color: 'lightblue',
    backgroundColor: 'rgb(26, 26, 26)',
    //backgroundImage: `url(${space_background})`,
    textAlign: 'center'
}

const Area_2Style = {
    color: 'yellow',
    backgroundColor: 'grey',
    textAlign: 'center'
}

const Area_Top_Style = {
    marginTop: "10px",
    color: 'lightblue',
    backgroundColor: 'grey',
    textAlign: 'center',
    fontText: 'Arial'
}

let divider = `.:*~*:._.:*~*:._.:*~*:._.:*~*:._.:*~*:._.:*~*:._.:*~*:._.:*~*:.`

export default Area_1;