import { useState } from "react"
import { GameServer } from '../classes/Gameserver'
import gameConfig from '../game_config.json'
import Bottombar from './Bottombar'
import Wallet from './Wallet'
import SymbolsArea from './SymbolArea'
import NukeCounter from './NukeCounter'
import IceCounter from './IceCounter'
import TopBar from './TopBar'
import SpinButton from './SpinButton'
import setTimeout from "promise-timers";



let gameState = JSON.parse(JSON.stringify(gameConfig.gameState))
let clientState = JSON.parse(JSON.stringify(gameConfig.clientState))
let gameserver = new GameServer(gameConfig)

const App = () => {
    
    const [thisGameState, setGameState] = useState(JSON.parse(JSON.stringify(gameConfig.gameState)))
    const [thisClientState, setClientState] = useState(JSON.parse(JSON.stringify(gameConfig.clientState)))
    return (
        <div id={"gameContainer"}>
            <TopBar gameState={gameState}></TopBar>
            <div id="gameArea">
                    <NukeCounter gameState={gameState}></NukeCounter>
                    <SymbolsArea gameState={gameState}></SymbolsArea>
                    <IceCounter gameState={gameState}></IceCounter>
            </div>
            <SpinButton gameState={gameState} clientState={clientState} setGameState={setGameState} setClientState={setClientState}></SpinButton>
            <Bottombar gameState={gameState} wallet={gameConfig.wallet}></Bottombar>
            <Wallet gameState={gameState} wallet={gameConfig.wallet}></Wallet>
        </div>
        )
}
    
    export default App

