import myMath from '../helpers/my_math.ts'
const TopBar = ({gameState}) => {

    let totalTbm = myMath.multiply(gameState.tbm_respin, gameState.broken_ice_respin)
    if(totalTbm === 0) {
        totalTbm = undefined
    }

    let frozenPhrase = undefined
    if(gameState.icePower > 0) {
         frozenPhrase = `Frozen ${gameState.icePower}`
    }

    let topBar_respin = 'topBar_respin'
    if(gameState.icePower > 0) {
        topBar_respin = 'topBar_respin_frozen'
    }

    let topBar_broken_ice = 'topBar_broken_ice'
    if(gameState.icePower > 0) {
        topBar_broken_ice = 'topBar_broken_ice_frozen'
    }

    return (
        <div id='topBar_container'>
            <div id="topBar_Syms_wins">RESPIN WINS »</div>
            <div id={topBar_respin}>{gameState.tbm_respin}</div>
            <div id="topBar_X">«X»</div>
            <div id={topBar_broken_ice}>{gameState.broken_ice_respin}</div>
            <div id="topBar_ice_multi">« ICE MULTI</div>
            <div></div>
            <div></div>
            <div id="a"><div id='blue'><div id="topBar_tbm">{totalTbm}</div></div></div>
            <div></div>
            <div>{frozenPhrase}</div>
        </div>
    )
}

export default TopBar

