  rngSymbols(gameState) {
    let nextAction = gameState.nextAction
    let symbols = gameState.symbols
    let boxOfSymbols = []
    let boxOfSymbolsUnderIce = []
    let boxOfSymbolsWhenAllSpotsAreEmpty = []

    //IF TO MUCH FROZEN
    if(unfrozenSlotCounter(gameState.freezingPositions) <= gameConfig.changeWeightWhenUnfrozenSlots) {
      Object.keys(gameConfig.symbolWeightsWhenMostIsFrozen).forEach (symbol => {
        for (let i = 0; i < gameConfig.symbolWeightsWhenMostIsFrozen[symbol]; i++) {
          boxOfSymbols.push(parseInt(symbol))
        }
      })
    //WEIGHTS AFTER 1 NUKE
    } else if (gameState.nukeActivations === 1){
      Object.keys(gameConfig.nukeActivations1).forEach (symbol => {
        for (let i = 0; i < gameConfig.nukeActivations1[symbol]; i++) {
          boxOfSymbols.push(parseInt(symbol))
        }
      })
    
    //WEIGHTS AFTER 1 < NUKE
    } else if (gameState.nukeActivations > 1) {
      Object.keys(gameConfig.nukeActivationsPlus1).forEach (symbol => {
        for (let i = 0; i < gameConfig.nukeActivationsPlus1[symbol]; i++) {
          boxOfSymbols.push(parseInt(symbol))
        }
      })
    } else {
    //NORMAL SYMBOL DISTRIBUTION
      Object.keys(gameConfig.symbolWeights).forEach (symbol => {
        for (let i = 0; i < gameConfig.symbolWeights[symbol]; i++) {
          boxOfSymbols.push(parseInt(symbol))
        }
      })
    }

    Object.keys(gameConfig.symbolWeightsUnderIce).forEach (symbol => {
      for (let i = 0; i < gameConfig.symbolWeightsUnderIce[symbol]; i++) {
        boxOfSymbolsUnderIce.push(parseInt(symbol))
      }
    })

    Object.keys(gameConfig.symbolWeightsWhenAllSpotsAreEmpty).forEach (symbol => {
      for (let i = 0; i < gameConfig.symbolWeightsWhenAllSpotsAreEmpty[symbol]; i++) {
        boxOfSymbolsWhenAllSpotsAreEmpty.push(parseInt(symbol))
      }
    })


    function containsOnlyEmptySpots(symbols) {
      let onlyEmptySpots = true
      symbols.forEach (sym => {
        if(sym !== -1) {
          onlyEmptySpots = false
        }
      })
      return onlyEmptySpots
    }

    function unfrozenSlotCounter(iceSymbols) {
      let unfrozenSlots = 0
      iceSymbols.forEach (sym => {
        if(sym === -1) {
          unfrozenSlots++
        }
      })
      return unfrozenSlots
    }

    if(containsOnlyEmptySpots(symbols)) {
      symbols.forEach((symbol, index) => {
        symbols[index] = boxOfSymbolsWhenAllSpotsAreEmpty[Math.floor(Math.random() * boxOfSymbolsWhenAllSpotsAreEmpty.length)]
      })
    } else {
      symbols.forEach((symbol, index) => {
        if(gameConfig.keepFrozenBombs === true && symbol === 100 && gameState.freezingPositions[index] === 1) {
          symbols[index] = 100
        } else {
          // on action freespin all symnbols should replace [unless bombs], need fix for bombs
          if(nextAction === 'freespin') {
            if(gameState.freezingPositions[index] === 1) {
              symbols[index] = boxOfSymbolsUnderIce[Math.floor(Math.random() * boxOfSymbolsUnderIce.length)]
            } else {
              symbols[index] = boxOfSymbols[Math.floor(Math.random() * boxOfSymbols.length)]
            }
          } else if (symbol === -1) {
            //Empty spots are -1, so when action is not freespin [freerespin], we add new symbols.
            if(gameState.freezingPositions[index] === 1) {
              symbols[index] = boxOfSymbolsUnderIce[Math.floor(Math.random() * boxOfSymbolsUnderIce.length)]
            } else {
              symbols[index] = boxOfSymbols[Math.floor(Math.random() * boxOfSymbols.length)]
            }
          } else {
            //deadspin -> respin stopped
        }
        }
      })
    }
    
    
    //TEST
    //  symbols = [
    //   3, 3, 3, 3, 2, 2, 2, 2, 1, 1, 3, 1, 1, 4, 4, 4, 4, 5, 3, 3, 5, 6, 6, 6, 6, 4, 4, 7, 7, 8, 8, 8, 8, 2, 1, 1, 1, 8, 1, 6, 1, 1, 1, 8, 1, 1, 1, 1, 3, 7, 7, 7, 5, 8, 3, 1, 3, 2, 3, 3, 4, 4, 8, 1
    //  ]

    //symbols = [1,5,4,3,1,3,3,1,2,1,6,3,5,2,1,6,2,7,5,4,1,2,5,2,3,7,4,2,6,4,6,5,4,6,7,6,6,2,5,6,4,1,1,6,6,5,7,7,1,7,3,6,3,2,6,4,5,7,1,4,1,1,3,6]



    return symbols
  }

