    info.numberOfDeadspin.percent = myMath.multiply(myMath.divide(info.numberOfDeadspin.nr, gameRounds), 100)
    info.nukeInfo.percent = myMath.multiply(myMath.divide(info.nukeInfo.atleastOneNuke, gameRounds), 100)
