function getSymPos(winningSymbol, gameState) {
  let positions = [];
  gameState.symbols.forEach((symbol, index) => {
    if(symbol === winningSymbol && gameState.freezingPositions[index] !== 1) {
      positions.push(index)
    }
  });
  return positions
}

