import { setTimeout } from "promise-timers";

const SymbolArea = ({gameState}) => {

    let symbols = []
    gameState.symbols.forEach((symbol, index) => {
        switch (symbol) {
            case 1:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym1")} key={'sym'+index}>{symbol}</div>)
                break;
            case 2:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym2")} key={'sym'+index}>{symbol}</div>)
                break;
            case 3:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym3")} key={'sym'+index}>{symbol}</div>)
                break;
            case 4:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym4")} key={'sym'+index}>{symbol}</div>)
                break;
            case 5:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym5")} key={'sym'+index}>{symbol}</div>)
                break;
            case 6:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym6")} key={'sym'+index}>{symbol}</div>)
                break;
            case 7:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym7")} key={'sym'+index}>{symbol}</div>)
                break;
            case 8:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym8")} key={'sym'+index}>{symbol}</div>)
                break;
            case 9:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym9")} key={'sym'+index}>{symbol}</div>)
                break;
            case 100:
                symbols.push(<div className={isFrozenIndex(gameState, index, "sym100")} key={'sym'+index}></div>)
                break;
            case -1:
                symbols.push(<div className={isFrozenIndex(gameState, index, "empty")} key={'sym'+index}>{symbol}</div>)
                break;
            default:
                console.warn('DONT RECON THE SYMBOL? SymbolArea')
        }

    });

    return (
      <div id="symbolGrid">{symbols}</div>
    )
}

//<h3 style={bottombarStyle}>{`Flares: ${gameState.flares}`}</h3>
const bottombarStyle = {
    color: 'blue',
    backgroundColor: 'darkgrey',
    paddingLeft: "5px"
}

export default SymbolArea


function isFrozenIndex(gameState, index, className) {
    if(gameState.freezingPositions[index] === 1) {
       return className += " frozen"
    } else {
        return className
    }
}